// AppointmentsScheduledEventAttributes Scheduled events
type AppointmentsScheduledEventAttributes struct {
	// Comments Please share anything that will help prepare for our meeting.
	Comments *string `json:"comments,omitempty"`

	// CreatedAt Added
	CreatedAt *time.Time `json:"created_at,omitempty"`

	// EndOn End On
	EndOn *time.Time `json:"end_on,omitempty"`

	// EventType Event type information (can be null in rare cases if the event type has been deleted, but the event record wasn't)
	EventType *struct {
		// Name The display name of the scheduled event, typically including event type and invitee information
		Name *string `json:"name,omitempty"`
	} `json:"event_type,omitempty"`

	// Id Scheduled event ID
	Id int `json:"id"`

	// MaxInvitees Max Invitees
	MaxInvitees *int `json:"max_invitees,omitempty"`

	// OrderId Event Payment Order
	OrderId *string `json:"order_id,omitempty"`

	// PrimaryContact Scheduled events
	PrimaryContact *struct {
		// EmailAddress The email address of the primary invitee for this scheduled event
		EmailAddress *string `json:"email_address,omitempty"`

		// FirstName The first name of the primary invitee for this scheduled event
		FirstName *string `json:"first_name,omitempty"`

		// Id Scheduled event ID
		Id int `json:"id"`

		// LastName The last name of the primary invitee for this scheduled event
		LastName *string `json:"last_name,omitempty"`

		// PhoneNumber The phone number of the primary invitee for this scheduled event
		PhoneNumber *string `json:"phone_number,omitempty"`

		// PublicId The unique public identifier for the scheduled event
		PublicId *string `json:"public_id,omitempty"`
	} `json:"primary_contact,omitempty"`

	// PublicId The unique public identifier for the scheduled event
	PublicId *string `json:"public_id,omitempty"`

	// StartOn Event Start Time
	StartOn time.Time `json:"start_on"`

	// Status Status
	Status *string `json:"status,omitempty"`

	// Tzid Timezone
	Tzid *string `json:"tzid,omitempty"`

	// UpdatedAt Updated
	UpdatedAt *time.Time `json:"updated_at,omitempty"`

	// WorkspaceId Workspace ID
	WorkspaceId int `json:"workspace_id"`
}

