// ConditionalSplitStepAttributes **BETA** — Conditional Split Steps are currently in beta. You can request access via the [Funnel Coders community](https://developers.myclickfunnels.com/page/code-support) but keep in mind that BETA endpoints are subject to change.
//
// A conditional split step routes contacts down one of two branches based on whether
// they match a contact filter (`condition`). Each branch carries the
// `show_page_step` + `page` attached to that branch (both `null` when the branch is
// empty). The first branch (`branches[0]`) is the **matched** branch; the second
// (`branches[1]`) is the **unmatched** branch.
//
// See the [Funnels Skill](https://accounts.myclickfunnels.com/.well-known/funnels/skill.md#conditional-split-steps) for the full conditional-split surface (positioning, multi-page branches, attaching filters).
//
// The `condition.filter_id` is the public id of a RefineFilter scoped to the same workspace.
// Pass it on PATCH to attach or replace the filter. Create filters first via `POST /api/v2/workspaces/{workspace_id}/refine_filters` — see [Attaching a filter](https://accounts.myclickfunnels.com/.well-known/funnels/skill.md#attaching-a-filter) and the cross-link to [Applying filters to conditional split steps](https://accounts.myclickfunnels.com/.well-known/refine-filters/skill.md#applying-filters-to-conditional-split-steps).
//
// On `GET /funnels/{funnel_id}/conditional_split_steps/{id}` (show), `condition.filter` is always
// included as a full RefineFilter object. On the list endpoint it is included only when
// `expand[]=filter` is passed.
type ConditionalSplitStepAttributes struct {
	// Branches Ordered branches — `[matched, unmatched]`.
	Branches []struct {
		// Page The page attached to this branch, or null if empty.
		Page *struct {
			Id       *int    `json:"id,omitempty"`
			Name     *string `json:"name,omitempty"`
			PublicId *string `json:"public_id,omitempty"`
		} `json:"page,omitempty"`

		// ShowPageStep The ShowPageStep function attached to this branch, or null if empty.
		ShowPageStep *struct {
			CurrentPath *string `json:"current_path,omitempty"`
			Id          *int    `json:"id,omitempty"`
			Name        *string `json:"name,omitempty"`
			PublicId    *string `json:"public_id,omitempty"`
		} `json:"show_page_step,omitempty"`
	} `json:"branches"`
	Condition struct {
		// Filter **BETA** — RefineFilters are currently in beta. You can request access via the [Funnel Coders community](https://developers.myclickfunnels.com/page/code-support) but keep in mind that BETA endpoints are subject to change.
		//
		// A reusable workspace-scoped audience filter composed of one or more criteria joined by a single conjunction.
		//
		// Public API requests are validated against a [safe-condition whitelist](https://accounts.myclickfunnels.com/.well-known/refine-filters/skill.md#safe-condition-whitelist); criteria outside the whitelist return 422 with a pointer to the developer community.
		Filter *RefineFilterAttributes `json:"filter,omitempty"`

		// FilterId Public id of the attached RefineFilter. `null` when no filter has been set up.
		FilterId *string `json:"filter_id,omitempty"`

		// IsSetup True when a filter has been attached and the conditional split is ready to evaluate.
		IsSetup *bool `json:"is_setup,omitempty"`
	} `json:"condition"`
	CreatedAt *time.Time `json:"created_at,omitempty"`

	// FunnelId ID of the funnel containing this conditional split
	FunnelId *int `json:"funnel_id,omitempty"`

	// FunnelPublicId Obfuscated funnel ID
	FunnelPublicId *string `json:"funnel_public_id,omitempty"`

	// Id Conditional split step ID
	Id int `json:"id"`

	// PublicId Obfuscated conditional split step ID
	PublicId  *string    `json:"public_id,omitempty"`
	UpdatedAt *time.Time `json:"updated_at,omitempty"`
}

// ConditionalSplitStepParametersCreate **BETA** — Conditional Split Steps are currently in beta. You can request access via the [Funnel Coders community](https://developers.myclickfunnels.com/page/code-support) but keep in mind that BETA endpoints are subject to change.
//
// Parameters for adding a new conditional split step to a funnel's workflow. The split
// always starts as a 2-branch tree (`matched` first, `unmatched` second). All fields
// below are optional — providing none creates an empty unconfigured split that
// the caller can fill in later via PATCH.
//
// ### `condition`
//
// Supply `filter_id` — the public id of a RefineFilter scoped to the same workspace.
// Create filters first via `POST /api/v2/workspaces/{workspace_id}/refine_filters`.
// Raw numeric ids are rejected for cross-tenant safety. See [Attaching a filter](https://accounts.myclickfunnels.com/.well-known/funnels/skill.md#attaching-a-filter)
// and [Applying filters to conditional split steps](https://accounts.myclickfunnels.com/.well-known/refine-filters/skill.md#applying-filters-to-conditional-split-steps).
//
// ### Branches
//
// Optional `branches` array — up to 2 entries; `branches[0]` is the matched branch,
// `branches[1]` is the unmatched branch. Each entry may carry either:
//
//   - `page_id` — a single fresh `user_page` id to attach as the branch's first step.
//   - `page_ids` — an array of fresh `user_page` ids to attach in order. Use this to
//     build a branch with multiple sequential pages (e.g. matched users see Welcome →
//     Onboarding → CTA, while unmatched users see Email Capture → Welcome).
//
// `page_id` and `page_ids` are mutually exclusive per branch entry. Each page
// referenced must be in the same workspace and not already wired to any
// `ShowPageStep` anywhere.
//
// ### Positioning
//
// See `show_page_step_id` semantics — identical to the split test step endpoint.
type ConditionalSplitStepParametersCreate struct {
	ConditionalSplitStep *struct {
		// Branches Optional 0..2 branch entries; `branches[0]` is the matched branch, `branches[1]` is the unmatched branch.
		Branches *[]struct {
			// PageId Optional fresh `user_page` id to attach as the branch's first step. Mutually exclusive with `page_ids`.
			PageId *int `json:"page_id,omitempty"`

			// PageIds Optional list of fresh `user_page` ids to attach in order under this branch.
			// Use this to build branches with multiple sequential steps. Mutually exclusive with `page_id`.
			PageIds *[]int `json:"page_ids,omitempty"`
		} `json:"branches,omitempty"`
		Condition *struct {
			// FilterId Public id of a RefineFilter in this workspace. Create filters via `POST /api/v2/workspaces/{workspace_id}/refine_filters`.
			FilterId *string `json:"filter_id,omitempty"`
		} `json:"condition,omitempty"`

		// ShowPageStepId Optional. Insert the new conditional split AFTER the workflow step that wraps
		// this `show_page_step`. Accepts a numeric `Workflows::Steps::ShowPageStep` id
		// or its obfuscated public id (you can read either off any page response).
		// When omitted, the split lands at funnel entry.
		ShowPageStepId *int `json:"show_page_step_id,omitempty"`
	} `json:"conditional_split_step,omitempty"`
}

// ConditionalSplitStepParametersUpdate **BETA** — Conditional Split Steps are currently in beta. You can request access via the [Funnel Coders community](https://developers.myclickfunnels.com/page/code-support) but keep in mind that BETA endpoints are subject to change.
//
// Update the `condition` and/or attach pages to existing `branches`. At least one of
// the two must be provided.
//
//   - `condition.filter_id` is the public id of a RefineFilter in the same workspace.
//     Create or update filters via the RefineFilter endpoints. See [Attaching a filter](https://accounts.myclickfunnels.com/.well-known/funnels/skill.md#attaching-a-filter)
//     and [Applying filters to conditional split steps](https://accounts.myclickfunnels.com/.well-known/refine-filters/skill.md#applying-filters-to-conditional-split-steps).
//   - `branches` must be a 2-entry array (matched, unmatched).
//   - `page_id` (single) — when the branch is empty: attach. When the branch already
//     has show-page-steps: swap the FIRST step's page (subsequent steps preserved).
//   - `page_ids` (array) — APPEND the listed fresh pages to the end of the branch.
//     Use this to grow a branch with more sequential steps over multiple PATCHes.
//     Both forms are mutually exclusive per entry; any page referenced must be a
//     fresh `user_page` in the same workspace with no existing ShowPageStep.
type ConditionalSplitStepParametersUpdate struct {
	ConditionalSplitStep *struct {
		Branches *[]struct {
			// PageId Page id to attach (currently empty branch) or swap (first step on populated branch). Mutually exclusive with `page_ids`.
			PageId *int `json:"page_id,omitempty"`

			// PageIds List of fresh page ids to APPEND to the end of this branch. Mutually exclusive with `page_id`.
			PageIds *[]int `json:"page_ids,omitempty"`
		} `json:"branches,omitempty"`
		Condition *struct {
			// FilterId Public id of a RefineFilter in this workspace.
			FilterId *string `json:"filter_id,omitempty"`
		} `json:"condition,omitempty"`
	} `json:"conditional_split_step,omitempty"`
}

