// ContactParameters Contacts
type ContactParameters struct {
	// CustomAttributes Custom attributes are usually added in ClickFunnels to a contact when they submit forms that contain custom contact attributes. Here you can directly create them during contact modification.
	//
	// Custom attributes are provided as key-value pairs:
	// A key that does not exist, will create a new custom contact attribute.
	// A key that already exists, will update the value of an existing custom contact attribute.
	//
	// Empty or null values, will set the custom attribute values to empty strings. A key that has special characters or spaces will be automatically converted to `snake_case` (For example, 'Favorite Food! 🥑' will be converted to 'favorite_food').
	//
	// Empty keys will trigger a bad request response. Also, non-object inputs for custom_attributes (e.g. an array or string), it will be ignored.
	// Keys that are default properties on the Contact resource or variations of it will result in an error. E.g., 'first_name', 'First Name',  etc. are not valid inputs.
	CustomAttributes *map[string]string `json:"custom_attributes,omitempty"`

	// EmailAddress Email address
	EmailAddress *string `json:"email_address,omitempty"`

	// FbUrl Facebook URL
	FbUrl *string `json:"fb_url,omitempty"`

	// FirstName First name
	FirstName *string `json:"first_name,omitempty"`

	// InstagramUrl Instagram URL
	InstagramUrl *string `json:"instagram_url,omitempty"`

	// LastName Last name
	LastName *string `json:"last_name,omitempty"`

	// LinkedinUrl LinkedIn URL
	LinkedinUrl *string `json:"linkedin_url,omitempty"`

	// PhoneNumber Phone number
	PhoneNumber *string `json:"phone_number,omitempty"`

	// TagIds Contact Tag IDs. Any valid array, empty or with valid tags will overwrite existing values. To avoid losing existing tags first use the Fetch Contact endpoint, then be sure to include the existing tags in your payload along with any new addition(s).
	TagIds *[]int `json:"tag_ids,omitempty"`

	// TimeZone The human-readable time zone, usually set dynamically by the app for the contact, for example, during opt-in.
	// Read more about time zones and how to map them back to the TZ standard in [our Time Zones guide.](https://dash.readme.com/project/cf2/v2/docs/timezones).
	TimeZone *string `json:"time_zone,omitempty"`

	// TwitterUrl Twitter URL
	TwitterUrl *string `json:"twitter_url,omitempty"`

	// WebsiteUrl Website URL
	WebsiteUrl *string `json:"website_url,omitempty"`
}

