// EmailsBroadcastAttributes Email Broadcasts
type EmailsBroadcastAttributes struct {
	// CompleteAt Timestamp when sending completed
	CompleteAt time.Time `json:"complete_at"`

	// CreatedAt Created at datetime
	CreatedAt time.Time `json:"created_at"`

	// ExternalId An optional external identifier for tracking purposes
	ExternalId string `json:"external_id"`

	// FilterId The audience filter determining which contacts receive this broadcast. Numeric `Refine::StoredFilter` id (not the public id).
	// Create the filter via `POST /api/v2/workspaces/{workspace_id}/refine_filters` and pass the response's `id` field. See [Applying filters to email broadcasts](https://accounts.myclickfunnels.com/.well-known/refine-filters/skill.md#applying-filters-to-email-broadcasts).
	FilterId int `json:"filter_id"`

	// FromEmail The sender email address
	FromEmail string `json:"from_email"`

	// FromName The sender display name associated with the from address
	FromName string `json:"from_name"`

	// HtmlBody HTML content of the email
	HtmlBody string `json:"html_body"`

	// Id Broadcast ID
	Id int `json:"id"`

	// Name Internal name for the broadcast
	Name string `json:"name"`

	// OriginationChannelId The ID of the origination channel
	OriginationChannelId int `json:"origination_channel_id"`

	// OriginationChannelType The type of origination channel that created this broadcast
	OriginationChannelType string `json:"origination_channel_type"`

	// Preheadline Preview text shown in email clients before opening (max 150 characters)
	Preheadline string `json:"preheadline"`

	// PublicId Broadcast public ID
	PublicId string `json:"public_id"`

	// ReplyToEmail The reply-to email address
	ReplyToEmail string `json:"reply_to_email"`

	// SendAt Scheduled send date
	SendAt string `json:"send_at"`

	// SendAtLocalTime Scheduled send time in HH:MM:SS format, relative to the specified time zone
	SendAtLocalTime string `json:"send_at_local_time"`

	// SendImmediately Whether the broadcast sends immediately upon creation
	SendImmediately bool `json:"send_immediately"`

	// SendingAt Timestamp when sending actually began
	SendingAt time.Time `json:"sending_at"`

	// Status Current broadcast status. New broadcasts start as draft.
	Status EmailsBroadcastAttributesStatus `json:"status"`

	// Subject Email subject line seen by recipients
	Subject string `json:"subject"`

	// TextBody Plain text content of the email
	TextBody string `json:"text_body"`

	// TimeZone Time zone for scheduled sending
	TimeZone string `json:"time_zone"`

	// TopicIds IDs of topics associated with this broadcast
	TopicIds []int `json:"topic_ids"`

	// UpdatedAt Updated at datetime
	UpdatedAt time.Time `json:"updated_at"`

	// WorkspaceId Workspace ID
	WorkspaceId int `json:"workspace_id"`
}

// EmailsBroadcastAttributesStatus Current broadcast status. New broadcasts start as draft.
type EmailsBroadcastAttributesStatus string

// EmailsBroadcastParameters Email Broadcasts
type EmailsBroadcastParameters struct {
	// ExternalId An optional external identifier for your own tracking
	ExternalId *string `json:"external_id,omitempty"`

	// FilterId Audience filter id (numeric). If recipients are provided, a filter is created automatically.
	// Otherwise pass the numeric `id` of a `Refine::StoredFilter` created via the [Refine Filters Skill](https://accounts.myclickfunnels.com/.well-known/refine-filters/skill.md). See [Applying filters to email broadcasts](https://accounts.myclickfunnels.com/.well-known/refine-filters/skill.md#applying-filters-to-email-broadcasts).
	FilterId *int `json:"filter_id,omitempty"`

	// FromEmail Sender email address. Required on create. Must be a verified email address that belongs to the workspace.
	FromEmail string `json:"from_email"`

	// HtmlBody HTML email body. If provided without a template_id, a template is automatically created from this content.
	HtmlBody *string `json:"html_body,omitempty"`

	// Name Internal name for the broadcast (required)
	Name string `json:"name"`

	// Preheadline Preview text shown in email clients before opening. Maximum 150 characters.
	Preheadline *string `json:"preheadline,omitempty"`

	// Recipients List of recipients (maximum 1,000). Contacts are created or matched by email address.
	Recipients *[]struct {
		// Email Recipient email address (required)
		Email string `json:"email"`

		// FirstName Recipient first name
		FirstName *string `json:"first_name,omitempty"`

		// LastName Recipient last name
		LastName *string `json:"last_name,omitempty"`
	} `json:"recipients,omitempty"`

	// ReplyToEmail Reply-to email address. Must be a verified address in the workspace if provided.
	ReplyToEmail *string `json:"reply_to_email,omitempty"`

	// SendAt Scheduled send date. Required when send_immediately is false.
	SendAt *string `json:"send_at,omitempty"`

	// SendAtLocalTime Scheduled send time in HH:MM:SS format. Defaults to 18:00:00.
	SendAtLocalTime *string `json:"send_at_local_time,omitempty"`

	// SendImmediately Set to true to send the broadcast immediately upon creation. If false, use send_at, send_at_local_time, and time_zone to schedule.
	SendImmediately *bool `json:"send_immediately,omitempty"`

	// Subject Email subject line seen by recipients
	Subject *string `json:"subject,omitempty"`

	// TemplateId ID of an existing email template to use. Alternative to providing html_body/text_body directly.
	TemplateId *int `json:"template_id,omitempty"`

	// TextBody Plain text email body
	TextBody *string `json:"text_body,omitempty"`

	// TimeZone Time zone for scheduling (defaults to workspace time zone)
	TimeZone *string `json:"time_zone,omitempty"`

	// TopicIds Topic IDs to associate. Only topics belonging to the workspace are accepted.
	TopicIds *[]int `json:"topic_ids,omitempty"`
}

