// OrderParameters Parameters for creating external orders. External orders are orders managed outside of ClickFunnels payment processors (Payments AI or Stripe).
//
// **Required fields:**
// - `order_type`: Must be `one-time-order` or `subscription-order`
// - `live_mode`: Must be `true` or `false`
// - `contact_id` or `contact_attributes`: Either provide a `contact_id` directly, or use `contact_attributes` with an `email_address` to look up an existing contact
// - `line_items_attributes`: At least one line item with `variant_id`, `products_price_id`, and `quantity`
//
// **Note:** For one-time orders, line items must reference one-time products. For subscription orders, line items can include both one-time and subscription products.
type OrderParameters struct {
	// ActivatedAt Date Activated
	ActivatedAt *string `json:"activated_at,omitempty"`

	// BillingAddressCity The city of the billing address.
	BillingAddressCity *string `json:"billing_address_city,omitempty"`

	// BillingAddressCountry The billing address country.
	BillingAddressCountry *string `json:"billing_address_country,omitempty"`

	// BillingAddressPostalCode Billing address postal (ZIP) code.
	BillingAddressPostalCode *string `json:"billing_address_postal_code,omitempty"`

	// BillingAddressRegion The region of the shipping address, like state or province.
	BillingAddressRegion *string `json:"billing_address_region,omitempty"`

	// BillingAddressStreetOne The main street information of the billing address, including the street name and number.
	BillingAddressStreetOne *string `json:"billing_address_street_one,omitempty"`

	// BillingAddressStreetTwo Additional street information of the billing address, like entrance information and apartment numbers.
	BillingAddressStreetTwo *string `json:"billing_address_street_two,omitempty"`

	// BillingStatus The billing status reflects the status of the invoice of an order.
	// Billing status can be one of the following for Payments AI and Stripe orders:
	// `pending`, `draft`, `paid`, `unpaid`, `partially-refunded`, `refunded`, `voided`, `disputed`, `past-due`.
	//
	// For external orders, the billing status can be one of: `pending`, `paid`, `unpaid`, `voided` and `refunded`.
	BillingStatus *string `json:"billing_status,omitempty"`

	// CancelDescription A free-text description of the cancellation reason.
	CancelDescription *string `json:"cancel_description,omitempty"`

	// CancelReason The reason _code_ for the cancelation, it is required when canceling an order.
	//
	// Possible codes for Payments AI orders are:
	// `did-not-use`, `did-not-want`, `missing-features`, `too-expensive`, `bugs-or-problems`, `other`
	//
	// Possible codes for Stripe orders are:
	// `customer_service`, `low_quality`, `missing_features`, `other`, `switched_service`, `too_complex`, `too_expensive`, `unused`
	//
	// External orders accept the same cancelation reasons as Stripe.
	CancelReason *string `json:"cancel_reason,omitempty"`

	// CanceledAt Order Canceled At
	CanceledAt *string `json:"canceled_at,omitempty"`

	// CanceledBy Order Canceled By
	CanceledBy *string `json:"canceled_by,omitempty"`

	// ChurnedAt Churned At
	ChurnedAt *string `json:"churned_at,omitempty"`

	// ContactAttributes Alternative to `contact_id`. Provide contact attributes to look up an existing contact by email.
	// The contact must already exist in the workspace - by default, this does not create new contacts.
	// If `contact_id` is also provided, it takes precedence and `contact_attributes` is ignored.
	ContactAttributes *struct {
		// EmailAddress The email address of an existing contact in the workspace. Required when using contact_attributes.
		EmailAddress string `json:"email_address"`
	} `json:"contact_attributes,omitempty"`

	// ContactId The ID of the contact associated with the order.
	// Either `contact_id` or `contact_attributes` must be provided, but not both.
	// If both are provided, `contact_id` takes precedence.
	ContactId *int `json:"contact_id,omitempty"`

	// ExternalId An external ID, e.g., a payment provider's ID or an ID managed by the client internally
	ExternalId *string `json:"external_id,omitempty"`

	// LineItemsAttributes Line items for the order. At least one line item is required.
	// Each line item must include a valid `variant_id`, `products_price_id`, and `quantity`.
	LineItemsAttributes []struct {
		// ProductsPriceId The ID of the price for the product. Must be a valid price for the variant's product.
		ProductsPriceId int `json:"products_price_id"`

		// Quantity The quantity of this line item.
		Quantity int `json:"quantity"`

		// VariantId The ID of the product variant. Must be a valid variant in your workspace.
		VariantId int `json:"variant_id"`
	} `json:"line_items_attributes"`

	// LiveMode Required. Indicates if the Order is for production or testing.
	// - `true`: The order is a live/production order.
	// - `false`: The order is a test order.
	LiveMode bool `json:"live_mode"`

	// NextChargeAt The date and time of the next scheduled charge for subscription orders. (External subscription orders only)
	NextChargeAt *string `json:"next_charge_at,omitempty"`

	// Notes Your internal note about the order. This will be visible in ClickFunnels admin orders-related sections.
	Notes *string `json:"notes,omitempty"`

	// OrderType The type of order. Required for creating orders.
	// - `one-time-order`: A single purchase order. Line items must reference one-time products only.
	// - `subscription-order`: A recurring subscription order. Line items can include both one-time and subscription products.
	OrderType OrderParametersOrderType `json:"order_type"`

	// ServiceStatus The service status reflects the activity state of the order. For subscriptions, it can control whether a subscription is ongoing, for example despite an irregular (unpaid) invoice status.
	//
	// For orders with Payments AI as the payment processor, it can be one of the following:
	// `pending`, `active`, `completed`, `churned`, `canceled`, `suspended`, `paused`, `abandoned`, `voided`
	// Stripe orders have the same order statuses, except for `voided`. For voided invoices, its service status becomes `abandoned`.
	// You can read about the state transitions in more detail in our [orders overview guide](https://developers.myclickfunnels.com/docs/orders).
	//
	// For external one-time orders possible service statuses are `pending` or `completed`. For external subscription orders possible statuses are `pending`, `active`, `churned`, `canceled`, `completed`, `paused`.
	ServiceStatus *string `json:"service_status,omitempty"`

	// ShippingAddressCity The city of the shipping address.
	ShippingAddressCity *string `json:"shipping_address_city,omitempty"`

	// ShippingAddressCountry The country of the shipping address.
	ShippingAddressCountry *string `json:"shipping_address_country,omitempty"`

	// ShippingAddressFirstName The first name of the recipient's shipping address.
	ShippingAddressFirstName *string `json:"shipping_address_first_name,omitempty"`

	// ShippingAddressLastName The last name of the recipient's shipping address.
	ShippingAddressLastName *string `json:"shipping_address_last_name,omitempty"`

	// ShippingAddressOrganizationName The organization name of the recipient's shipping address.
	ShippingAddressOrganizationName *string `json:"shipping_address_organization_name,omitempty"`

	// ShippingAddressPhoneNumber The phone number of the recipient's shipping address.
	ShippingAddressPhoneNumber *string `json:"shipping_address_phone_number,omitempty"`

	// ShippingAddressPostalCode Postal Code
	ShippingAddressPostalCode *string `json:"shipping_address_postal_code,omitempty"`

	// ShippingAddressRegion The region of the shipping address, like state or province.
	ShippingAddressRegion *string `json:"shipping_address_region,omitempty"`

	// ShippingAddressStreetOne The main street information of the shipping address, including the street name and number.
	ShippingAddressStreetOne *string `json:"shipping_address_street_one,omitempty"`

	// ShippingAddressStreetTwo Additional street information for the shipping address, like entrance information and apartment numbers.
	ShippingAddressStreetTwo *string `json:"shipping_address_street_two,omitempty"`
}

