// OrdersLineItemsChangeRequest Parameters to preview or commit a subscription line item variant/price change
type OrdersLineItemsChangeRequest struct {
	OrdersLineItemsChange struct {
		// EffectiveTime Optional override for when the change takes effect. When omitted (or `null`,
		// or an empty string), the in-app default is used: upgrades take effect now,
		// downgrades at the next renewal. Any other value (e.g. `end_of_period` or a
		// literal timestamp) returns 422.
		EffectiveTime *OrdersLineItemsChangeRequestOrdersLineItemsChangeEffectiveTime `json:"effective_time,omitempty"`

		// ProductsPriceId Target price. Accepts either the integer database id or the obfuscated
		// `public_id` string returned by the discovery endpoint. The target variant is
		// derived from the price's `variant` association.
		ProductsPriceId string `json:"products_price_id"`

		// Prorate Optional override for proration. Accepts `true`, `false`, `"true"`, `"false"`,
		// `"1"`, `"0"`, `1`, or `0`. When omitted, the in-app default is used:
		// upgrades are prorated and applied immediately; downgrades are not prorated and
		// take effect at the end of the current billing cycle. Forced to `false` for
		// physical line items regardless of the value sent. Any other value returns 422.
		Prorate *bool `json:"prorate,omitempty"`
	} `json:"orders_line_items_change"`
}

// OrdersLineItemsChangeRequestOrdersLineItemsChangeEffectiveTime Optional override for when the change takes effect. When omitted (or `null`,
// or an empty string), the in-app default is used: upgrades take effect now,
// downgrades at the next renewal. Any other value (e.g. `end_of_period` or a
// literal timestamp) returns 422.
type OrdersLineItemsChangeRequestOrdersLineItemsChangeEffectiveTime string

// OrdersLineItemsChangeResponse Result of a subscription line item variant/price change. The same envelope is returned
// for both preview and commit endpoints — the `preview` flag indicates which.
//
// `upcoming_invoice` is a snapshot of the upcoming-invoice impact of the change as quoted
// by the upstream payment platform. It is **informational** — the line item is mutated
// regardless of whether the quote succeeds. On commit, the quote is snapshotted just
// before the change is applied so consumers don't need a separate preview round-trip
// to know what their customer will be charged. Individual amount fields may be `null`
// if the upstream quote returned no data; `currency` and `next_invoice_date` fall back
// to the order's stored currency and renewal date in that case.
type OrdersLineItemsChangeResponse struct {
	OrdersLineItemsChange struct {
		// NewLineItem The line item as it would be after the change (preview) or as it now is after
		// the change (commit) — same `id` as the current line item, with `products_price`
		// and `products_variant` reflecting the target.
		NewLineItem OrdersLineItemAttributes `json:"new_line_item"`

		// Preview `true` for the preview endpoint, `false` for the commit endpoint. The remainder
		// of the envelope is shaped identically; the flag lets clients render the same UI
		// or write the same parsing code for both calls.
		Preview bool `json:"preview"`

		// PreviousLineItem The line item as it was before the change — same `id` as the current line item,
		// but with `products_price` and `products_variant` reflecting the pre-change
		// target.
		PreviousLineItem OrdersLineItemAttributes `json:"previous_line_item"`

		// UpcomingInvoice Snapshot of the upcoming-invoice impact of the change as quoted by the upstream
		// payment platform. Populated on both preview and commit (commit snapshots a quote
		// inside the change transaction so the response carries the same fields as preview).
		// Informational only — the line item change is committed regardless of whether the
		// quote succeeds.
		UpcomingInvoice struct {
			// Currency Currency of the upcoming invoice quote. Falls back to the order's stored
			// currency if the quote returned no data.
			Currency string `json:"currency"`

			// DiscountAmount Upcoming invoice discount quoted by the payment platform. `null` if the quote returned no data.
			DiscountAmount *string `json:"discount_amount,omitempty"`

			// NextInvoiceDate Upcoming invoice date as quoted by the payment platform. Falls back to the
			// order's stored renewal date if the quote returned no data.
			NextInvoiceDate time.Time `json:"next_invoice_date"`

			// ShippingAmount Upcoming invoice shipping quoted by the payment platform. `null` if the quote returned no data.
			ShippingAmount *string `json:"shipping_amount,omitempty"`

			// SubtotalAmount Upcoming invoice subtotal quoted by the payment platform. `null` if the quote returned no data.
			SubtotalAmount *string `json:"subtotal_amount,omitempty"`

			// TaxAmount Upcoming invoice tax quoted by the payment platform. `null` if the quote returned no data.
			TaxAmount *string `json:"tax_amount,omitempty"`

			// TotalAmount Upcoming invoice total quoted by the payment platform. `null` if the quote returned no data.
			TotalAmount *string `json:"total_amount,omitempty"`
		} `json:"upcoming_invoice"`
	} `json:"orders_line_items_change"`
}

