// SplitTestStepAttributes A split test step wraps an existing page in a funnel in a two-branch split. Each
// variant carries the `show_page_step` + `page` attached to that branch (both `null`
// when the branch is empty), plus the branch's traffic `weight` (0..100).
type SplitTestStepAttributes struct {
	CreatedAt *time.Time `json:"created_at,omitempty"`

	// Funnel The funnel containing this split test.
	Funnel *struct {
		// Id Funnel ID
		Id *int `json:"id,omitempty"`

		// Name Funnel name
		Name *string `json:"name,omitempty"`

		// PublicId Obfuscated funnel ID
		PublicId *string `json:"public_id,omitempty"`
	} `json:"funnel,omitempty"`

	// Id Split test step ID
	Id int `json:"id"`

	// PublicId Obfuscated split test step ID
	PublicId  *string    `json:"public_id,omitempty"`
	UpdatedAt *time.Time `json:"updated_at,omitempty"`

	// Variants Ordered variants. Binary split tests always have 2 entries.
	Variants []struct {
		// Page The page attached to this branch, or null if empty.
		Page *struct {
			Id       *int    `json:"id,omitempty"`
			Name     *string `json:"name,omitempty"`
			PublicId *string `json:"public_id,omitempty"`
		} `json:"page,omitempty"`

		// ShowPageStep The ShowPageStep function attached to this branch, or null if empty.
		ShowPageStep *struct {
			CurrentPath *string `json:"current_path,omitempty"`
			Id          *int    `json:"id,omitempty"`
			Name        *string `json:"name,omitempty"`
			PublicId    *string `json:"public_id,omitempty"`
		} `json:"show_page_step,omitempty"`

		// Weight Percentage of traffic sent to this branch (0..100). Branches must sum to 100.
		Weight *int `json:"weight,omitempty"`
	} `json:"variants"`
}

// SplitTestStepParametersCreate Parameters for wrapping an existing page in a new split test. Provide 1 or 2 variants.
// The first variant's `page_id` must already be attached to a step in this funnel's
// workflow (that page gets wrapped). The second variant's `page_id` must be a fresh page
// (not already used by any step anywhere). No cloning occurs.
//
// ### Positioning the split
//
// By default (no `show_page_step_id`), the split lands at the funnel entry —
// `sort_order 0` under the workflow root — with all surviving steps moved into a
// `Root Step after Sequence End` convergence sequence positioned right after the split.
//
// When `show_page_step_id` references an existing show-page step in this funnel, the
// split is inserted **after that step** under the same parent, and steps
// N+1...end are migrated under the convergence sequence. This is the "split between
// step N and step N+1" shape.
type SplitTestStepParametersCreate struct {
	SplitTestStep struct {
		// ShowPageStepId Optional. Insert the new split AFTER the workflow step that wraps this
		// `show_page_step`. Accepts a numeric `Workflows::Steps::ShowPageStep` id
		// or its obfuscated public id (you can read either off any page response).
		// When omitted, the split lands at funnel entry.
		ShowPageStepId *int `json:"show_page_step_id,omitempty"`

		// Variants 1 or 2 variant entries.
		Variants []struct {
			// PageId Page ID (required on the first variant; optional on the second).
			PageId *int `json:"page_id,omitempty"`

			// Weight Traffic weight (0..100). Either omit on both variants (defaults 100/0 for 1 variant or 50/50 for 2) or provide on both.
			Weight *int `json:"weight,omitempty"`
		} `json:"variants"`
	} `json:"split_test_step"`
}

// SplitTestStepParametersUpdate Parameters for updating a split test's variants. The `variants` array length must
// equal the current number of branches (2 for the standard binary case). Each entry may
// provide any subset of `{ page_id, weight }`.
type SplitTestStepParametersUpdate struct {
	SplitTestStep struct {
		Variants []struct {
			// PageId New page to attach/swap to this branch. Must be a fresh page (no existing ShowPageStep).
			PageId *int `json:"page_id,omitempty"`

			// Weight Traffic weight (0..100). If any variant provides weight, all must — and they must sum to 100.
			Weight *int `json:"weight,omitempty"`
		} `json:"variants"`
	} `json:"split_test_step"`
}

